#!/usr/bin/env node

const fs = require('node:fs');
const { stat, writeFile } = require('node:fs/promises');
const readline = require('node:readline');

const {
  RAW_AUDIT_JSONL_PATH,
  CODEOWNERS_BY_FILENAME_JSON_PATH,
